import assert from 'node:assert';

import {
  XRANGER_BOUNDARY_THEOREM_IDS,
  auditXRangerBoundaryManifest,
  createXRangerBoundaryManifest,
  xRangerFloorProbability,
  xRangerWeakestInspectionFloor,
  type CreateXRangerBoundaryManifestInput,
} from '../lib';

const BASE_INPUT: CreateXRangerBoundaryManifestInput = {
  generatedAt: '2026-04-18T22:00:00.000Z',
  policy: {
    stateClasses: [
      {
        id: 'control-plane',
        localPortClass: 'system',
        remotePortClass: 'operator',
        protocol: 'https',
        direction: 'ingress',
        trustTier: 'control-plane',
      },
      {
        id: 'external-web',
        localPortClass: 'public-web',
        remotePortClass: 'internet',
        protocol: 'tcp',
        direction: 'ingress',
        trustTier: 'public',
      },
    ],
    actions: ['quarantine', 'allow', 'snapshot', 'mirror'],
    inspectionFloors: [
      {
        action: 'quarantine',
        numerator: 1,
        denominator: 48,
      },
      {
        action: 'mirror',
        numerator: 1,
        denominator: 24,
      },
    ],
    certificationMode: 'local-quorum-globalized',
    reconstructionMode: 'spec-boundary',
    prismShroud: {
      mode: 'delayed-attested-route',
      privacyModel: 'accountability',
    },
  },
};

const manifestA = createXRangerBoundaryManifest(BASE_INPUT);
const manifestB = createXRangerBoundaryManifest({
  ...BASE_INPUT,
  theoremIds: [...XRANGER_BOUNDARY_THEOREM_IDS].reverse(),
  policy: {
    ...BASE_INPUT.policy,
    stateClasses: [...BASE_INPUT.policy.stateClasses].reverse(),
    actions: [...BASE_INPUT.policy.actions].reverse(),
    inspectionFloors: [...BASE_INPUT.policy.inspectionFloors].reverse(),
  },
});

assert.deepStrictEqual(manifestA, manifestB);
assert.strictEqual(manifestA.kind, 'x-ranger-boundary');
assert.strictEqual(manifestA.version, 1);
assert.strictEqual(manifestA.shell.packageRoot, 'open-source/x-ranger');
assert.strictEqual(
  manifestA.manager.packageRoot,
  'open-source/x-ranger/gnosis-ranger'
);
assert.strictEqual(manifestA.manager.transportFront, 'gnosis-uring');
assert.strictEqual(manifestA.manager.futureTarget, 'lambda');
assert.deepStrictEqual(manifestA.policy.actions, [
  'allow',
  'mirror',
  'quarantine',
  'snapshot',
]);
assert.deepStrictEqual(
  manifestA.policy.stateClasses.map((stateClass) => stateClass.id),
  ['control-plane', 'external-web']
);
assert.strictEqual(
  xRangerFloorProbability(manifestA.policy.inspectionFloors[0]),
  1 / 24
);
assert.strictEqual(
  xRangerWeakestInspectionFloor(manifestA.policy.inspectionFloors),
  1 / 48
);

const audit = auditXRangerBoundaryManifest(manifestA);
assert.strictEqual(audit.selfConsistent, true);
assert.deepStrictEqual(audit.issues, []);
assert.strictEqual(audit.weakestInspectionFloor, 1 / 48);

const driftedDigest = auditXRangerBoundaryManifest({
  ...manifestA,
  digest: `broken-${manifestA.digest}`,
});
assert.strictEqual(driftedDigest.selfConsistent, false);
assert.ok(
  driftedDigest.issues.includes(
    'digest does not match the canonical x-ranger boundary body'
  )
);

const missingInspectionAction = auditXRangerBoundaryManifest({
  ...manifestA,
  policy: {
    ...manifestA.policy,
    actions: ['allow', 'drop'],
  },
});
assert.strictEqual(missingInspectionAction.selfConsistent, false);
assert.ok(
  missingInspectionAction.issues.includes(
    "inspection floor action 'mirror' must also appear in policy actions"
  )
);
assert.ok(
  missingInspectionAction.issues.includes(
    "inspection floor action 'quarantine' must also appear in policy actions"
  )
);

console.log('x-ranger-boundary: all tests passed');
